class Node {
  int value;
  Node left, right;
}

boolean contains(Node root, int target) {
  Node current = root;
  while (current != null) {
    if (target == current.value) return true;
    if (target < current.value) current = current.left;
    else current = current.right;
  }
  return false;
}
